def __getattr__(name: str) -> Any:
    return getattr(parent, name)

def _profile_uses_d1d5(profile: str) -> bool:
    return profile in {PROFILE_D1D5_D512, PROFILE_D1D5_D512_KCAPACITY_Q128, PROFILE_ALL}

def _profile_uses_d512(profile: str) -> bool:
    return profile in {PROFILE_D1D5_D512, PROFILE_D1D5_D512_KCAPACITY_Q128, PROFILE_ALL}

def _profile_uses_kcapacity_q128(profile: str) -> bool:
    return profile in {PROFILE_D1D5_D512_KCAPACITY_Q128, PROFILE_ALL}

def _profile_uses_kcapacity_k64(profile: str) -> bool:
    return profile == PROFILE_ALL

def _profile_guard_order(profile: str) -> list[str]:
    if profile == PROFILE_BASE_9286:
        return parent._guard_order()
    guards: list[str] = []
    if _profile_uses_d1d5(profile):
        guards.append(str(_D1D5_ENTRY['shape_key']))
    if _profile_uses_d512(profile):
        guards.append(str(_D512_ENTRY['shape_key']))
    if _profile_uses_kcapacity_q128(profile):
        guards.extend((str(entry['shape_key']) for entry in _KCAPACITY_ENTRIES[:2]))
    if _profile_uses_kcapacity_k64(profile):
        guards.append(str(_KCAPACITY_ENTRIES[2]['shape_key']))
    guards.extend(parent._guard_order())
    return guards

def _parent_info(inputs: dict[str, Any], profile: str) -> dict[str, Any]:
    info = dict(parent.route_info(inputs))
    route = str(info.get('route') or info.get('selected_route') or parent.selected_route(inputs))
    info['profile'] = profile
    info['route'] = route
    info['selected_route'] = route
    info['guard_order'] = _profile_guard_order(profile)
    info.setdefault('production_policy', 'weave_only')
    info.setdefault('external_fallback', None)
    info.setdefault('coverage_only', False)
    info.setdefault('missing_weave_route', False)
    return info

def _seed_info(inputs: dict[str, Any], profile: str, entry: dict[str, Any], *, coverage_only: bool | None=None) -> dict[str, Any]:
    parent_info = dict(parent.route_info(inputs))
    parent_route = str(parent_info.get('route') or parent_info.get('selected_route') or parent.selected_route(inputs))
    is_coverage_only = bool(entry.get('coverage_only', False) if coverage_only is None else coverage_only)
    return {'profile': profile, 'route': entry['route'], 'selected_route': entry['route'], 'selected_entrypoint': entry['entrypoint'], 'parent_route': parent_route, 'replaced_route': parent_route, 'route_kind': 'coverage-only' if is_coverage_only else 'specialized', 'route_source': 'shape-specific-seed', 'coverage_class': entry['coverage_class'], 'classification': 'coverage-only' if is_coverage_only else 'seed-consumed', 'coverage_only': is_coverage_only, 'production_policy': 'weave_only', 'external_fallback': None, 'guard_order': _profile_guard_order(profile), 'guard_id': entry['shape_key'], 'forced_fallback': False, 'selected_guard': entry['guard'], 'fallback': parent_route, 'missing_weave_route': False, 'source_task': entry['source_task'], 'source_round_doc': entry['source_round_doc'], 'selected_seed': entry['selected_seed'], 'selected_seed_task': entry['source_task'], 'replaced_seed': parent_info.get('selected_seed')}

def _use_d1d5(inputs: dict[str, Any], profile: str) -> bool:
    return _profile_uses_d1d5(profile) and d1d5._shape_guard(inputs)

def _use_d512(inputs: dict[str, Any], profile: str) -> bool:
    return _profile_uses_d512(profile) and d512._use_d512_q64_tcgen05(inputs)

def _use_kcapacity_q128_k40(inputs: dict[str, Any], profile: str) -> bool:
    return _profile_uses_kcapacity_q128(profile) and (not bool(inputs.get('force_fallback', False))) and kcapacity._use_q128_m131072_k40(inputs)

def _use_kcapacity_q128_k56(inputs: dict[str, Any], profile: str) -> bool:
    return _profile_uses_kcapacity_q128(profile) and (not bool(inputs.get('force_fallback', False))) and kcapacity._use_q128_m65536_k56(inputs)

def _use_kcapacity_q4096_k64(inputs: dict[str, Any], profile: str) -> bool:
    return _profile_uses_kcapacity_k64(profile) and (not bool(inputs.get('force_fallback', False))) and kcapacity._use_q4096_m49152_k64(inputs)

def selected_route_for_profile(inputs: dict[str, Any], profile: str) -> str:
    if profile not in {PROFILE_BASE_9286, PROFILE_D1D5_D512, PROFILE_D1D5_D512_KCAPACITY_Q128, PROFILE_ALL}:
        raise ValueError(''.join(['unknown synthesized kNN dispatcher profile: ', format(profile, '')]))
    if _use_d1d5(inputs, profile):
        return ROUTE_EXT_DYNAMIC_D1D5
    if _use_d512(inputs, profile):
        return ROUTE_D512_Q64
    if _use_kcapacity_q128_k40(inputs, profile):
        return ROUTE_KCAPACITY_Q128_K40
    if _use_kcapacity_q128_k56(inputs, profile):
        return ROUTE_KCAPACITY_Q128_K56
    if _use_kcapacity_q4096_k64(inputs, profile):
        return ROUTE_KCAPACITY_Q4096_K64
    return parent.selected_route(inputs)

def selected_route(inputs: dict[str, Any]) -> str:
    return selected_route_for_profile(inputs, PROFILE_ALL)

def selected_route_name(inputs: dict[str, Any]) -> str:
    return selected_route(inputs)

def route_info_for_profile(inputs: dict[str, Any], profile: str) -> dict[str, Any]:
    if profile not in {PROFILE_BASE_9286, PROFILE_D1D5_D512, PROFILE_D1D5_D512_KCAPACITY_Q128, PROFILE_ALL}:
        raise ValueError(''.join(['unknown synthesized kNN dispatcher profile: ', format(profile, '')]))
    if _use_d1d5(inputs, profile):
        return _seed_info(inputs, profile, _D1D5_ENTRY)
    if _use_d512(inputs, profile):
        return _seed_info(inputs, profile, _D512_ENTRY)
    if _use_kcapacity_q128_k40(inputs, profile):
        return _seed_info(inputs, profile, _KCAPACITY_ENTRIES[0])
    if _use_kcapacity_q128_k56(inputs, profile):
        return _seed_info(inputs, profile, _KCAPACITY_ENTRIES[1])
    if _use_kcapacity_q4096_k64(inputs, profile):
        return _seed_info(inputs, profile, _KCAPACITY_ENTRIES[2])
    return _parent_info(inputs, profile)

def route_info(inputs: dict[str, Any]) -> dict[str, Any]:
    return route_info_for_profile(inputs, PROFILE_ALL)

def route_trace_entry(label: str, inputs: dict[str, Any], profile: str=PROFILE_ALL) -> dict[str, Any]:
    return {'label': label, 'shape_key': label, 'B': int(inputs['B']), 'Q': int(inputs['Q']), 'M': int(inputs['M']), 'D': int(inputs['D']), 'K': int(inputs['K']), 'self_search': bool(inputs.get('self_search', False)), **route_info_for_profile(inputs, profile)}

def launch_for_profile(inputs: dict[str, Any], profile: str) -> dict[str, Any]:
    if profile not in {PROFILE_BASE_9286, PROFILE_D1D5_D512, PROFILE_D1D5_D512_KCAPACITY_Q128, PROFILE_ALL}:
        raise ValueError(''.join(['unknown synthesized kNN dispatcher profile: ', format(profile, '')]))
    if _use_d1d5(inputs, profile):
        return d1d5.launch_for_eval(inputs)
    if _use_d512(inputs, profile):
        return d512.launch_for_eval(inputs)
    if _use_kcapacity_q128_k40(inputs, profile) or _use_kcapacity_q128_k56(inputs, profile) or _use_kcapacity_q4096_k64(inputs, profile):
        return kcapacity.launch_for_eval(inputs)
    return parent.launch_for_eval(inputs)

def launch_base_9286_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    return launch_for_profile(inputs, PROFILE_BASE_9286)

def launch_d1d5_d512_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    return launch_for_profile(inputs, PROFILE_D1D5_D512)

def launch_q128_kcapacity_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    return launch_for_profile(inputs, PROFILE_D1D5_D512_KCAPACITY_Q128)

def launch_current_portfolio_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    return launch_for_profile(inputs, PROFILE_ALL)

def launch_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    return launch_current_portfolio_for_eval(inputs)

def _select_contract_shapes(shape_labels: str | tuple[str, ...] | list[str] | None):
    if shape_labels is None:
        return EXT_SYNTHESIS_SHAPES
    return select_named_shapes(shape_labels)

def knn_search_compile_and_launch_dispatch0618_c492_9286_d1d5_d512_kcapacity(*, benchmark: bool=True, shape_labels: str | tuple[str, ...] | list[str] | None=EXT_SYNTHESIS_LABELS) -> dict[str, Any]:
    from .._dispatch_runtime import evaluate
    result = evaluate(launch_for_eval, shapes=_select_contract_shapes(shape_labels), benchmark=benchmark)
    result['passed'] = bool(result.get('summary', {}).get('all_correct'))
    print(result)
    return result

def knn_search_compile_and_launch_mma_split(*, benchmark: bool=True, shape_labels: str | tuple[str, ...] | list[str] | None=EXT_SYNTHESIS_LABELS) -> dict[str, Any]:
    return knn_search_compile_and_launch_dispatch0618_c492_9286_d1d5_d512_kcapacity(benchmark=benchmark, shape_labels=shape_labels)
